// Cyberia404.js — SSR "sector not found" page for the Cyberia MMO stack.
//
// A single static bundle served by BOTH the cyberia-server (Go static server)
// and the cyberia-client (python docker-driver) for any unmatched path. It is
// instance-aware: the same file is baked into every deployment variant, and it
// resolves its own sub-path at runtime so links and the normalised URL point
// back at the right instance:
//   /FOREST/<bad> → the FOREST 404 (return → /FOREST/)
//   /TEST/<bad>   → the TEST 404   (return → /TEST/)
//   /<bad>        → the default 404 (return → /)
//
// Base path resolution (first hit wins):
//   1. window.CYBERIA_BASE_PATH — injected by the serving layer from the
//      deployment's CYBERIA_BASE_PATH env ("/FOREST", "/TEST", "" for default).
//      Authoritative: only the runtime knows its own instance prefix, since the
//      reverse proxy strips it before the backend sees the request.
//   2. Fallback: the first URL path segment, minus a trailing "/404".
//
// Visual contract: cyberpunk-MMORPG pixel art — Press Start 2P / VT323, neon
// cyan/magenta on near-black, hard edges, scanlines, RGB-split glitch. Fully
// self-contained: pixel faces are embedded woff2 data URIs, every glyph is
// inline SVG or CSS — no font CDN, no external assets, no build step.

const s = (el) => document.querySelector(el);
const append = (el, htmlStr) => s(el).insertAdjacentHTML('beforeend', htmlStr);

// The instance sub-path this 404 belongs to ("/FOREST", "/TEST", or "" default).
// Prefer the injected value; fall back to the first URL segment (dropping a
// trailing "/404" so the page is idempotent once already normalised).
const basePath = () => {
  const injected = window.CYBERIA_BASE_PATH;
  if (typeof injected === 'string') return injected === '/' ? '' : injected.replace(/\/$/, '');
  const seg = (window.location.pathname || '/').split('/').filter(Boolean)[0] || '';
  return !seg || seg === '404' ? '' : `/${seg}`;
};

const homeHref = () => `${basePath()}/`;
const notFoundHref = () => `${basePath()}/404`;

// Instance label shown on the badge — the code the sub-path maps to, or MAIN.
const instanceLabel = () => {
  const b = basePath();
  return b ? b.replace(/^\//, '').toUpperCase() : 'MAIN';
};

const main = () => {
  // Normalise the URL to <base>/404 so a bad path reads as the instance's 404
  // (e.g. /FOREST/nope → /FOREST/404) without a server round-trip or a loop.
  const target = notFoundHref();
  if (window.location.pathname !== target) window.history.replaceState(null, '', target + window.location.search);

  append(
    'body',
    html`
      <style>
        /* Pixel faces embedded as woff2 data URIs (latin subset) so the page is
           fully self-contained — no font CDN dependency at the server runtime. */
        @font-face {
          font-family: 'Press Start 2P';
          font-style: normal;
          font-weight: 400;
          font-display: swap;
          src: url(data:font/woff2;base64,) format('woff2');
        }
        @font-face {
          font-family: 'VT323';
          font-style: normal;
          font-weight: 400;
          font-display: swap;
          src: url(data:font/woff2;base64,) format('woff2');
        }
        :root {
          --bg: #05060a;
          --bg-2: #0b0f18;
          --grid: #12305a;
          --fg: #cfe8ff;
          --dim: #5f7fa5;
          --cyan: #22d3ee;
          --magenta: #ff2e88;
          --green: #7ee787;
          --amber: #f0b429;
        }
        * {
          box-sizing: border-box;
        }
        html,
        body {
          margin: 0;
          height: 100%;
          background: var(--bg);
          color: var(--fg);
          font-family: 'VT323', ui-monospace, monospace;
          font-size: 20px;
          letter-spacing: 0.5px;
          overflow: hidden;
          image-rendering: pixelated;
          -webkit-font-smoothing: none;
        }
        /* Perspective neon grid floor. */
        body::before {
          content: '';
          position: fixed;
          inset: 0;
          background:
            radial-gradient(120% 80% at 50% -10%, rgba(34, 211, 238, 0.12), transparent 60%),
            linear-gradient(180deg, var(--bg) 40%, var(--bg-2) 100%);
          z-index: 0;
        }
        .grid {
          position: fixed;
          left: 50%;
          bottom: -10vh;
          width: 300vw;
          height: 70vh;
          transform: translateX(-50%) perspective(40vh) rotateX(62deg);
          background-image: linear-gradient(var(--grid) 2px, transparent 2px),
            linear-gradient(90deg, var(--grid) 2px, transparent 2px);
          background-size: 44px 44px;
          opacity: 0.5;
          animation: scroll 1.6s linear infinite;
          z-index: 0;
        }
        @keyframes scroll {
          to {
            background-position:
              0 44px,
              0 0;
          }
        }
        /* CRT scanlines. */
        body::after {
          content: '';
          position: fixed;
          inset: 0;
          pointer-events: none;
          background: repeating-linear-gradient(
            to bottom,
            rgba(0, 0, 0, 0) 0,
            rgba(0, 0, 0, 0) 2px,
            rgba(0, 0, 0, 0.35) 3px
          );
          z-index: 3;
          mix-blend-mode: multiply;
        }
        .wrap {
          position: relative;
          z-index: 2;
          height: 100%;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          text-align: center;
          padding: 24px;
        }
        .badge {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          border: 2px solid var(--cyan);
          color: var(--cyan);
          padding: 4px 12px;
          font-family: 'Press Start 2P', monospace;
          font-size: 9px;
          letter-spacing: 2px;
          margin-bottom: 26px;
          box-shadow: 0 0 12px rgba(34, 211, 238, 0.35);
        }
        .badge .dot {
          width: 8px;
          height: 8px;
          background: var(--green);
          box-shadow: 0 0 8px var(--green);
          animation: blink 1.2s steps(2) infinite;
        }
        @keyframes blink {
          50% {
            opacity: 0.25;
          }
        }
        /* Glitchy 404 with RGB channel split. */
        .code {
          position: relative;
          font-family: 'Press Start 2P', monospace;
          font-size: clamp(64px, 22vw, 200px);
          line-height: 1;
          color: var(--fg);
          text-shadow: 0 0 24px rgba(207, 232, 255, 0.25);
        }
        .code::before,
        .code::after {
          content: '404';
          position: absolute;
          inset: 0;
          clip-path: inset(0 0 0 0);
        }
        .code::before {
          color: var(--magenta);
          animation: glitch-a 2.2s infinite steps(2);
        }
        .code::after {
          color: var(--cyan);
          animation: glitch-b 2.6s infinite steps(2);
        }
        @keyframes glitch-a {
          0%,
          92%,
          100% {
            transform: translate(0, 0);
            opacity: 0;
          }
          93% {
            transform: translate(-4px, 2px);
            opacity: 0.9;
          }
          97% {
            transform: translate(3px, -2px);
            opacity: 0.7;
          }
        }
        @keyframes glitch-b {
          0%,
          90%,
          100% {
            transform: translate(0, 0);
            opacity: 0;
          }
          91% {
            transform: translate(4px, -2px);
            opacity: 0.9;
          }
          96% {
            transform: translate(-3px, 2px);
            opacity: 0.6;
          }
        }
        .headline {
          font-family: 'Press Start 2P', monospace;
          font-size: clamp(12px, 3vw, 20px);
          letter-spacing: 3px;
          color: var(--magenta);
          margin: 18px 0 6px;
          text-shadow: 0 0 10px rgba(255, 46, 136, 0.5);
        }
        .sub {
          color: var(--dim);
          font-size: 22px;
          max-width: 560px;
          line-height: 1.3;
        }
        .path {
          color: var(--amber);
          word-break: break-all;
        }
        .btn {
          display: inline-flex;
          align-items: center;
          gap: 10px;
          margin-top: 34px;
          padding: 12px 22px;
          border: 2px solid var(--cyan);
          background: rgba(34, 211, 238, 0.08);
          color: var(--cyan);
          font-family: 'Press Start 2P', monospace;
          font-size: 11px;
          letter-spacing: 2px;
          text-decoration: none;
          transition:
            background 0.1s,
            color 0.1s;
        }
        .btn:hover {
          background: var(--cyan);
          color: var(--bg);
          box-shadow: 0 0 18px rgba(34, 211, 238, 0.6);
        }
        .btn svg {
          width: 14px;
          height: 14px;
          fill: currentColor;
          shape-rendering: crispEdges;
        }
        .foot {
          position: fixed;
          bottom: 12px;
          left: 0;
          right: 0;
          text-align: center;
          color: var(--dim);
          font-size: 14px;
          letter-spacing: 2px;
          z-index: 2;
        }
      </style>
      <div class="grid"></div>
      <main class="wrap">
        <span class="badge"><span class="dot"></span> INSTANCE ${instanceLabel()}</span>
        <div class="code" data-text="404">404</div>
        <div class="headline">SIGNAL LOST</div>
        <p class="sub">
          Sector <span class="path">${window.location.pathname.replace(/[<>&"]/g, '')}</span> is not on the grid.<br />
          The coordinates you jacked into don't resolve to any node.
        </p>
        <a class="btn" href="${homeHref()}">
          <svg viewBox="0 0 12 12" aria-hidden="true">
            <path d="M6 1L1 5v6h3V8h4v3h3V5z" />
          </svg>
          RETURN TO ${instanceLabel()}
        </a>
      </main>
      <div class="foot">CYBERIA ONLINE // ERR_SECTOR_NOT_FOUND</div>
    `,
  );
};

SrrComponent = () =>
  html`<script>
    {
      const s = ${s};
      const append = ${append};
      const basePath = ${basePath};
      const homeHref = ${homeHref};
      const notFoundHref = ${notFoundHref};
      const instanceLabel = ${instanceLabel};
      const main = ${main};
      window.onload = main;
    }
  </script>`;
